import { useState } from "react"
import "./index.css"

function App() {
  const [count, setCount] = useState(0)

  return (
    <div className="min-h-screen bg-0 text-white flex flex-col items-center justify-center p-4">
      {/* Header */}
      <header className="mb-12 max-w-xl w-full">
        <h1 className="text-5xl md:text-6xl font-extrabold tracking-tight text-transparent bg-clip-text bg-gradient-to-r from-indigo-400 to-pink-400 mb-2">
          Simple Counter App
        </h1>
        <p className="text-lg text-muted max-w-md mx-auto">A clean, dark mode counter built with React and Tailwind CSS.</p>
      </header>

      {/* Counter Display */}
      <div className="flex flex-col items-center gap-6 mb-12">
        <div className="text-8xl sm:text-9xl font-black transition-all duration-300 ease-out transform scale-95 hover:scale-105">
          {count.toLocaleString()}
        </div>
        <p className="text-lg text-muted tracking-wider uppercase">Current Count</p>
      </div>

      {/* Button Group */}
      <div className="flex gap-6 justify-center">
        {/* Decrement Button */}
        <button
          onClick={() => setCount(c => Math.max(0, c - 1))}
          disabled={count <= 0}
          className={`button ${count === 0 ? 'opacity-50 cursor-not-allowed' : 'bg-gradient-to-r from-indigo-600 to-pink-600 hover:from-indigo-700 hover:to-pink-700'} text-white font-bold py-4 px-12 rounded-xl shadow-lg transition-all duration-300 transform active:scale-[0.98]`}
          aria-label={`Decrement count to ${count - 1}`}
        >
          -
        </button>

        {/* Increment Button */}
        <button
          onClick={() => setCount(c => c + 1)}
          className={`button bg-gradient-to-r from-pink-600 to-purple-600 hover:from-pink-700 hover:to-purple-700 text-white font-extrabold py-4 px-12 rounded-xl shadow-2xl transition-all duration-300 transform active:scale-[0.98]`}
          aria-label={`Increment count to ${count + 1}`}
        >
          +
        </button>
      </div>

      {/* Footer */}
      <footer className="mt-20 text-center text-sm text-dim">
        Built with React and Tailwind CSS | Tsunami AI Agent
      </footer>
    </div>
  )
}

export default App
